<?php if (!defined('__ROOT_DIR__')) exit; ?>
<!DOCTYPE html><html lang="zh"><head><meta charset="UTF-8"><?php require_once __ROOT_DIR__.'/shipsay/seo.php'; list($seo_title,$seo_keywords,$seo_description)=ss_seo_render('rank'); $title_arr=['allvisit'=>'总点击榜','monthvisit'=>'月点击榜','weekvisit'=>'周点击榜','dayvisit'=>'日点击榜','allvote'=>'总推荐榜','monthvote'=>'月推荐榜','weekvote'=>'周推荐榜','dayvote'=>'日推荐榜','goodnum'=>'收藏榜']; $current_query=isset($query)&&$query?(string)$query:'allvisit'; $current_title=isset($title_arr[$current_query])?$title_arr[$current_query]:'排行榜'; $rank_detail_base_raw=!empty($rank_detail_base)?rtrim((string)$rank_detail_base,'/').'/':''; if(trim((string)$seo_title)===''||trim((string)$seo_title)===SITE_NAME)$seo_title=$current_title.'_'.SITE_NAME; if(trim((string)$seo_keywords)===''||trim((string)$seo_keywords)===SITE_NAME)$seo_keywords=$current_title.',排行榜,'.SITE_NAME; if(trim((string)$seo_description)===''||trim((string)$seo_description)===SITE_NAME)$seo_description=SITE_NAME.$current_title.'页面。'; ?><title><?=htmlspecialchars($seo_title, ENT_QUOTES, 'UTF-8')?></title><meta name="keywords" content="<?=htmlspecialchars($seo_keywords, ENT_QUOTES, 'UTF-8')?>"><meta name="description" content="<?=htmlspecialchars($seo_description, ENT_QUOTES, 'UTF-8')?>"><?php require_once __THEME_DIR__ . '/tpl_header.php';?></head><body><?php ss_render_page_top(['page_title' => $current_title, 'show_back' => true]); ?><div class="rank-page-head"><h1><?=htmlspecialchars($current_title, ENT_QUOTES, 'UTF-8')?></h1></div><div class="rank-tabs"><?php foreach($title_arr as $key=>$label): ?><?php if ($rank_detail_base_raw !== ''): ?><a href="<?=htmlspecialchars($rank_detail_base_raw.$key.'/', ENT_QUOTES, 'UTF-8')?>" class="<?=$current_query===$key?'active':''?>"><?=htmlspecialchars($label, ENT_QUOTES, 'UTF-8')?></a><?php endif; ?><?php endforeach; ?></div><ol class="rank-page-list"><?php if (!empty($articlerows) && is_array($articlerows)): foreach($articlerows as $k=>$v): if($k>=30) break; ?><li><span class="rank-num"><?=$k+1?></span><div class="rank-cover"><a href="<?=htmlspecialchars((string)$v['info_url'], ENT_QUOTES, 'UTF-8')?>"><img src="<?=htmlspecialchars((string)$v['img_url'], ENT_QUOTES, 'UTF-8')?>" alt="<?=htmlspecialchars((string)$v['articlename'], ENT_QUOTES, 'UTF-8')?>"></a></div><div class="rank-main"><a href="<?=htmlspecialchars((string)$v['info_url'], ENT_QUOTES, 'UTF-8')?>" class="rank-bookname"><?=htmlspecialchars((string)$v['articlename'], ENT_QUOTES, 'UTF-8')?></a><div class="rank-meta"><em>作者：<?=htmlspecialchars((string)$v['author'], ENT_QUOTES, 'UTF-8')?></em><?php if(!empty($v['sortname_2'])): ?><em><?=htmlspecialchars((string)$v['sortname_2'], ENT_QUOTES, 'UTF-8')?></em><?php endif; ?><em><?=intval($v['words_w'])?>万字</em></div><p><?=htmlspecialchars((string)$v['intro_des'], ENT_QUOTES, 'UTF-8')?></p></div></li><?php endforeach; else: ?><li class="rank-empty">暂无榜单数据</li><?php endif; ?></ol><?php require_once __THEME_DIR__ . '/tpl_footer.php'; ?>
